.darma-loader-linear-progress {
  position: relative;
  display: inline-block;
  width: 132px;
  height: 10px;
  overflow: hidden;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #6366f1) 15%, transparent);
}
.darma-loader-linear-progress::before {
  content: "";
  position: absolute;
  inset: 0 auto 0 0;
  width: 48%;
  border-radius: inherit;
  background: var(--loader-color, #6366f1);
  animation: darma-loader-linear-progress-progress 1.25s ease-in-out infinite;
}
@keyframes darma-loader-linear-progress-progress {
  0% { transform: translateX(-105%); }
  55%, 100% { transform: translateX(210%); }
}

.darma-loader-stepped-progress {
  display: inline-flex;
  gap: 8px;
  color: var(--loader-color, #6366f1);
}
.darma-loader-stepped-progress i {
  width: 18px;
  height: 18px;
  border-radius: 7px;
  background: currentColor;
  opacity: 0.25;
  animation: darma-loader-stepped-progress-step 1.2s ease-in-out infinite;
}
.darma-loader-stepped-progress i:nth-child(2) { animation-delay: 0.15s; }
.darma-loader-stepped-progress i:nth-child(3) { animation-delay: 0.3s; }
.darma-loader-stepped-progress i:nth-child(4) { animation-delay: 0.45s; }
@keyframes darma-loader-stepped-progress-step {
  0%, 100% { opacity: 0.22; transform: translateY(0); }
  45% { opacity: 1; transform: translateY(-6px); }
}
